  assert(attestation.routeManifest.publicApiRoutes.includes("/api/evaluation/opportunity-quality/history"), "runtimeAttestation route manifest must include opportunity quality history");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/evaluation/search-quality"), "runtimeAttestation route manifest must include search quality");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/evaluation/search-quality/plan"), "runtimeAttestation route manifest must include search quality plan");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/evaluation/search-quality/history"), "runtimeAttestation route manifest must include search quality history");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/graph-quality"), "runtimeAttestation route manifest must include graph quality");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/graph-quality/plan"), "runtimeAttestation route manifest must include graph quality plan");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/graph-quality/history"), "runtimeAttestation route manifest must include graph quality history");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/graph-crosslinks"), "runtimeAttestation route manifest must include graph crosslinks");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/graph-crosslinks/plan"), "runtimeAttestation route manifest must include graph crosslinks plan");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/graph-crosslinks/history"), "runtimeAttestation route manifest must include graph crosslinks history");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/graph-scoreboard"), "runtimeAttestation route manifest must include graph scoreboard");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/graph-scoreboard/plan"), "runtimeAttestation route manifest must include graph scoreboard plan");
  assert(attestation.routeManifest.publicApiRoutes.includes("/api/graph-scoreboard/history"), "runtimeAttestation route manifest must include graph scoreboard history");
