  assert(report.checks.every((check) => check.passed), "runtimeDiff fixture checks should pass");
  assert(report.checks.some((check) => check.id === "route-manifest"), "runtimeDiff route check missing");
  assert(report.checks.some((check) => check.id === "refresh-plan"), "runtimeDiff refresh check missing");
  assert(report.checks.some((check) => check.id === "script-coverage"), "runtimeDiff script check missing");
  assertStringArray(report.nonClaims, "runtimeDiff.nonClaims", 4);
  assert(report.nonClaims.some((item) => /CDN|provider/i.test(item)), "runtimeDiff CDN/provider non-claim missing");
  assertString(report.nextAction, "runtimeDiff.nextAction");
  assertString(report.verificationCommand, "runtimeDiff.verificationCommand");
  assert(plan.command === "npm run diff:runtime", "runtimeDiff plan command invalid");
