  assert(history.fullDetailEndpoint === "/api/evaluation/sample/history?detail=full", "evaluationSample history full detail endpoint invalid");
  assert(history.historyPayloadPolicy.fullDetail === false, "evaluationSample history policy invalid");
  assert(Buffer.byteLength(JSON.stringify(history)) < 2200, "evaluationSample compact history exceeds byte budget");
  assert(history.receipts[0].samplePreview.length <= 3, "evaluationSample history sample preview invalid");
  assert(!history.receipts[0].samples, "evaluationSample history should not expose full samples");
  assert(!(history.receipts[0].topRiskPreview || []).some((risk) => risk.repairAction), "evaluationSample history should compact repair prose");
  const fullHistory = buildEvaluationSampleHistory({ receipts: [historyReceipt], limit: 5, totalAvailable: 1, detail: "full" });
  assert(fullHistory.detail === "full", "evaluationSample full history detail invalid");
  assert(fullHistory.historyPayloadPolicy.fullDetail === true, "evaluationSample full history policy invalid");
  assert(fullHistory.receipts[0].samples[0].expectedFailureMode, "evaluationSample full history should preserve sample detail");
  assertNoSensitiveText(JSON.stringify(report), "evaluation sample report");
