function fixtureSearchResults(benchmark, claims) {
  return projects
    .slice()
    .sort((left, right) => {
      const leftExpected = benchmark.expectedSlugs.includes(left.slug) ? 1 : 0;
      const rightExpected = benchmark.expectedSlugs.includes(right.slug) ? 1 : 0;
      return rightExpected - leftExpected || right.score - left.score;
    })
    .slice(0, 5)
    .map((project) => {
      const projectClaims = claims.filter((claim) => claim.relatedProject === project.slug);
      return {
        slug: project.slug,
        title: project.title,
        confidenceScore: Math.round(projectClaims.reduce((sum, claim) => sum + claim.confidenceScore, 0) / projectClaims.length),
        evidenceSnippet: projectClaims[0]?.text || project.outcome,
        explanation: `Fixture search result for ${benchmark.query}.`,
        relatedClaims: projectClaims.slice(0, 3).map((claim) => claim.id),
      };
    });
}

function validationGraph({
  projects,
  claims,
  opportunities,
  artifactCatalog = { artifacts: [] },
  narratives = { narratives: [] },
  narrativeObjections = { audiences: [] },
  packets = { packets: [] },
  narrativeTailor = { audiences: [] },
}) {
  const objectionRecords = (narrativeObjections.audiences || []).flatMap((audience) =>
    audience.objections.map((objection) => ({ audience, objection })),
  );
  const tailoredRecords = (narrativeTailor.audiences || []).flatMap((audience) =>
    audience.variants.map((variant) => ({ audience, variant })),
  );
  const screenshotGaps = (artifactCatalog.gaps || []).filter((gap) => gap.gapType === "screenshot");
  const artifactGapRepairs = screenshotGaps
    .map((gap) => {
      const linkedOpportunities = (opportunities.opportunities || []).filter((opportunity) =>
        (opportunity.relatedProof || []).some((proof) => proof.slug === gap.project),
      );
      return {
        id: `artifact-gap-repair-${gap.id}`,
        gapId: gap.id,
        project: gap.project,
        label: `${gap.projectTitle} proof repair`,
        linkedOpportunityIds: linkedOpportunities.map((opportunity) => opportunity.id),
      };
    })
    .filter((item) => item.linkedOpportunityIds.length > 0);
  const nodes = [
    { id: "rishabh", label: "Rishabh", type: "person" },
    ...projects.map((project) => ({ id: project.slug, label: project.title, type: "project" })),
    ...claims.filter((claim) => claim.relatedProject).map((claim) => ({ id: claim.id, label: claim.text, type: "claim" })),
    ...opportunities.opportunities.map((opportunity) => ({ id: `opportunity-${opportunity.id}`, label: opportunity.label, type: "opportunity" })),
    ...(artifactCatalog.artifacts || []).map((artifact) => ({ id: artifact.id, label: artifact.label, type: "artifact" })),
    ...screenshotGaps.map((gap) => ({ id: `screenshot-${gap.id}`, label: gap.label, type: "screenshot" })),
    ...artifactGapRepairs.map((repair) => ({ id: repair.id, label: repair.label, type: "artifact-gap-repair", project: repair.project, gapId: repair.gapId })),
    ...(packets.packets || []).map((packet) => ({ id: `packet-${packet.id}`, label: packet.label, type: "audience-packet" })),
    ...(narratives.narratives || []).map((narrative) => ({ id: `narrative-${narrative.id}`, label: narrative.label, type: "narrative" })),
    ...tailoredRecords.map(({ audience, variant }) => ({
      id: `tailored-${audience.id}-${variant.id}`,
      label: `${audience.label}: ${variant.label}`,
      type: "tailored-narrative",
    })),
    ...objectionRecords.map(({ audience, objection }) => ({
      id: `objection-${audience.id}-${objection.id}`,
      label: objection.challenge,
      type: "narrative-objection",
    })),
  ];
  const edges = [
    ...projects.map((project) => ({
      source: "rishabh",
      target: project.slug,
      relation: "built",
      explanation: `${project.title} is modeled as a project.`,
    })),
    ...claims
      .filter((claim) => claim.relatedProject)
      .map((claim) => ({
        source: claim.relatedProject,
        target: claim.id,
        relation: "supports-claim",
        explanation: `${claim.relatedProject} supports ${claim.id}.`,
      })),
    ...opportunities.opportunities.flatMap((opportunity) =>
      opportunity.relatedProof.map((proof) => ({
        source: proof.slug,
        target: `opportunity-${opportunity.id}`,
        relation: "fits-opportunity",
        explanation: `${proof.slug} contributes to ${opportunity.id}.`,
      })),
    ),
    ...(artifactCatalog.artifacts || []).map((artifact) => ({
      source: artifact.project,
      target: artifact.id,
      relation: "has-artifact",
      explanation: `${artifact.project} exposes artifact ${artifact.id}.`,
    })),
    ...screenshotGaps.map((gap) => ({
      source: gap.project,
      target: `screenshot-${gap.id}`,
      relation: "needs-screenshot-artifact",
      explanation: `${gap.projectTitle} has an explicit screenshot gap.`,
    })),
    ...artifactGapRepairs.flatMap((repair) => [
      {
        source: repair.project,
        target: repair.id,
        relation: "has-artifact-gap-repair",
        explanation: `${repair.project} has a proof repair node for ${repair.gapId}.`,
      },
      {
        source: `screenshot-${repair.gapId}`,
        target: repair.id,
        relation: "planned-by-gap-repair",
        explanation: `${repair.gapId} is routed through proof repair.`,
      },
      ...repair.linkedOpportunityIds.map((opportunityId) => ({
        source: repair.id,
        target: `opportunity-${opportunityId}`,
        relation: "unblocks-opportunity-proof",
        explanation: `${repair.gapId} repair improves proof for ${opportunityId}.`,
      })),
    ]),
    ...(packets.packets || []).map((packet) => ({
      source: "rishabh",
      target: `packet-${packet.id}`,
      relation: "uses-audience-packet",
      explanation: `${packet.label} packages public-safe evidence.`,
    })),
    ...(narratives.narratives || []).map((narrative) => ({
      source: `packet-${narrative.id}`,
      target: `narrative-${narrative.id}`,
      relation: "grounds-narrative",
      explanation: `${narrative.label} is grounded from the audience packet.`,
    })),
    ...tailoredRecords.map(({ audience, variant }) => ({
      source: `narrative-${audience.id}`,
      target: `tailored-${audience.id}-${variant.id}`,
      relation: "tailors-narrative",
      explanation: `${audience.label} produces ${variant.label}.`,
    })),
    ...tailoredRecords.flatMap(({ audience, variant }) =>
      (variant.claimsUsed || [])
        .filter((claimId) => claims.some((claim) => claim.id === claimId))
        .slice(0, 4)
        .map((claimId) => ({
          source: `tailored-${audience.id}-${variant.id}`,
          target: claimId,
          relation: "tailored-narrative-uses-claim",
          explanation: `${variant.label} uses ${claimId}.`,
        })),
    ),
    ...tailoredRecords.flatMap(({ audience, variant }) =>
      (variant.artifactsUsed || [])
        .filter((artifactId) => (artifactCatalog.artifacts || []).some((artifact) => artifact.id === artifactId))
        .slice(0, 4)
        .map((artifactId) => ({
          source: `tailored-${audience.id}-${variant.id}`,
          target: artifactId,
          relation: "tailored-narrative-cites-artifact",
          explanation: `${variant.label} cites ${artifactId}.`,
        })),
    ),
    ...objectionRecords.map(({ audience, objection }) => ({
      source: `narrative-${audience.id}`,
      target: `objection-${audience.id}-${objection.id}`,
      relation: "pressure-tested-by",
      explanation: `${audience.label} is pressure-tested by ${objection.id}.`,
    })),
    ...objectionRecords.flatMap(({ audience, objection }) =>
      (audience.sourceProjects || []).map((slug) => ({
        source: `objection-${audience.id}-${objection.id}`,
        target: slug,
        relation: "concerns-project",
        explanation: `${objection.id} concerns ${slug}.`,
      })),
    ),
    ...objectionRecords.flatMap(({ audience, objection }) =>
      (objection.evidence || [])
        .filter((id) => claims.some((claim) => claim.id === id))
        .map((claimId) => ({
          source: `objection-${audience.id}-${objection.id}`,
          target: claimId,
          relation: "answered-by-claim",
          explanation: `${objection.id} is answered by ${claimId}.`,
        })),
    ),
    ...objectionRecords.flatMap(({ audience, objection }) =>
      (objection.evidence || [])
        .filter((id) => (artifactCatalog.artifacts || []).some((artifact) => artifact.id === id))
        .map((artifactId) => ({
          source: `objection-${audience.id}-${objection.id}`,
          target: artifactId,
          relation: "answered-by-artifact",
          explanation: `${objection.id} is answered by ${artifactId}.`,
        })),
    ),
    ...objectionRecords.flatMap(({ audience, objection }) =>
      (objection.evidence || [])
        .filter((id) => String(id).startsWith("packet."))
        .map((evidenceId) => ({
          source: `objection-${audience.id}-${objection.id}`,
          target: `packet-${audience.id}`,
          relation: "uses-packet-disclosure",
          explanation: `${objection.id} uses packet disclosure ${evidenceId}.`,
        })),
    ),
    ...objectionRecords.flatMap(({ audience, objection }) =>
      (objection.evidence || [])
        .filter((id) => String(id).startsWith(`narrative.${audience.id}`))
        .map((evidenceId) => ({
          source: `objection-${audience.id}-${objection.id}`,
          target: `narrative-${audience.id}`,
          relation: "uses-narrative-disclosure",
          explanation: `${objection.id} uses narrative disclosure ${evidenceId}.`,
        })),
    ),
  ];
  return { nodes, edges };
}

function assertString(value, label) {
  assert(typeof value === "string" && value.trim().length > 0, `${label} must be a nonempty string`);
}

function assertStringArray(value, label, minLength) {
  assert(Array.isArray(value) && value.length >= minLength, `${label} must be an array with at least ${minLength} item(s)`);
  value.forEach((item, index) => assertString(item, `${label}[${index}]`));
}

function assertSlug(value, label) {
  assert(typeof value === "string" && /^[a-z0-9-]+$/.test(value), `${label} must be a lowercase slug`);
}

function assertGradient(value, label) {
  assert(Array.isArray(value) && value.length === 2, `${label} must have two colors`);
  value.forEach((color, index) => assert(/^#[0-9a-f]{6}$/i.test(color), `${label}[${index}] must be a hex color`));
}

function assertOptionalUrl(value, label) {
  if (value === null || value === undefined) return;
  assertUrl(value, label);
}

function assertUrl(value, label) {
  assertString(value, label);
  try {
    const parsed = new URL(value);
    assert(["http:", "https:", "mailto:"].includes(parsed.protocol), `${label} protocol must be http, https, or mailto`);
  } catch {
    errors.push(`${label} must be a valid URL`);
  }
}

function assertPublicUrl(value, label) {
  if (String(value).startsWith("/")) {
    assert(/^\/[a-z0-9/_ .-]*$/i.test(value), `${label} must be an internal public path`);
    return;
  }
  assertUrl(value, label);
}

function assertUnique(values, label) {
  const seen = new Set();
  for (const value of values) {
    if (seen.has(value)) errors.push(`${label} must be unique: ${value}`);
    seen.add(value);
  }
}

function assertNoSensitiveText(value, label) {
  const patterns = [
    [/\/Users\/[A-Za-z0-9_-]+/, "local user path"],
    [/(api[_-]?key|secret|token|password)\s*[:=]/i, "credential-like text"],
    [/sk-[A-Za-z0-9]{16,}/, "API key"],
    [/-----BEGIN [A-Z ]+PRIVATE KEY-----/, "private key"],
  ];
  for (const [pattern, name] of patterns) {
    if (pattern.test(value)) errors.push(`${label} contains ${name}`);
  }
}

function assert(condition, message) {
  if (!condition) errors.push(message);
}
